import React, { createContext, useContext, useEffect, useRef, useState, useCallback } from 'react';

// WebSocket Context
const WebSocketContext = createContext(null);

// WebSocket Provider 组件
export function WebSocketProvider({ children, url = 'ws://localhost:8765' }) {
    const [isConnected, setIsConnected] = useState(false);
    const [lastMessage, setLastMessage] = useState(null);
    const [error, setError] = useState(null);
    const ws = useRef(null);
    const reconnectTimeout = useRef(null);
    const eventHandlers = useRef(new Map());

    // 连接 WebSocket
    const connect = useCallback(() => {
        try {
            ws.current = new WebSocket(url);

            ws.current.onopen = () => {
                console.log('WebSocket 连接成功');
                setIsConnected(true);
                setError(null);

            };

            ws.current.onmessage = (event) => {
                try {
                    const data = JSON.parse(event.data);
                    setLastMessage(data);

                    // 触发所有注册的事件处理器
                    eventHandlers.current.forEach((handler) => {
                        handler(data);
                    });
                } catch (err) {
                    console.error('解析消息失败:', err);
                }
            };

            ws.current.onerror = (event) => {
                console.error('WebSocket 错误:', event);
                setError('连接错误');
            };

            ws.current.onclose = () => {
                console.log('WebSocket 连接关闭');
                setIsConnected(false);

                // 5秒后自动重连
                reconnectTimeout.current = setTimeout(() => {
                    console.log('尝试重新连接...');
                    connect();
                }, 5000);
            };
        } catch (err) {
            console.error('创建 WebSocket 连接失败:', err);
            setError('连接失败');
        }
    }, [url]);

    // 发送消息
    const sendMessage = useCallback((data) => {
        if (ws.current && ws.current.readyState === WebSocket.OPEN) {
            const message = typeof data === 'string' ? data : JSON.stringify(data);
            ws.current.send(message);
            return true;
        } else {
            console.warn('WebSocket 未连接');
            return false;
        }
    }, []);

    // 注册消息处理器
    const onMessage = useCallback((handler) => {
        const id = Date.now() + Math.random();
        eventHandlers.current.set(id, handler);

        // 返回取消注册的函数
        return () => {
            eventHandlers.current.delete(id);
        };
    }, []);

    // 断开连接
    const disconnect = useCallback(() => {
        if (reconnectTimeout.current) {
            clearTimeout(reconnectTimeout.current);
        }
        if (ws.current) {
            ws.current.close();
        }
    }, []);

    // 组件挂载时连接
    useEffect(() => {
        connect();

        return () => {
            disconnect();
        };
    }, [connect, disconnect]);

    const value = {
        isConnected,
        lastMessage,
        error,
        sendMessage,
        onMessage,
        reconnect: connect,
        disconnect
    };

    return (
        <WebSocketContext.Provider value={value}>
            {children}
        </WebSocketContext.Provider>
    );
}

// 自定义 Hook: 使用 WebSocket
export function useWebSocket() {
    const context = useContext(WebSocketContext);
    if (!context) {
        throw new Error('useWebSocket 必须在 WebSocketProvider 内部使用');
    }
    return context;
}

// 自定义 Hook: 监听特定消息
export function useWebSocketMessage(callback) {
    const { onMessage } = useWebSocket();

    useEffect(() => {
        const unsubscribe = onMessage(callback);
        return unsubscribe;
    }, [onMessage, callback]);
}
